import React, { useState } from "react";
import RecipeModal from './RecipeModal'
import styled from 'styled-components';
import { FaStar } from 'react-icons/fa';
import { FaPlus } from 'react-icons/fa';

const RecipeDiv = styled.div`
    height: 350px;
    flex-basis: 230px;
    flex-grow: 1;
    border-radius: 8px;
    background-size: cover;
    font-family: 'Montserrat', sans-serif;
    position: relative;
    margin: 1rem;
    box-shadow: #8888 5px 5px 10px;
`
const RecipeName = styled.div`
    font-size: 20px;
    font-weight: bold;
    text-transform: uppercase;
    letter-spacing: 3px;
    text-align : center;
    border-radius: 8px 8px 0px 0px;
`

const RatingDiv = styled.div`
    font-size: 20px;
    text-align: center;
`

const RecipeDesc = styled.div`
    position: absolute;
    bottom: 0px;
    width: -webkit-fill-available;
    background-color: ${props => props.theme.beige};
    border-radius: 0px 0px 8px 8px;
    padding-top: 0.3rem;
    padding-bottom: 0.3rem;
`

const RecipeOverlay = styled.div`
    opacity: 0;
    position: absolute;
    background-color: #888888CC;
    width: -webkit-fill-available;
    height: -webkit-fill-available;
    border-radius: 8px;
    transition: opacity 0.5s;

    &:hover ${RecipeDiv}{
        opacity: 1;
    }

    &:hover{
        opacity: 1;
    }
`

const SeeMoreBtn = styled.div`
    font-size: 50px;
    text-align: center;
    padding-top: 140px;
`

const RecipeCard = ({recipe}) => {
    var rating = [];
    for(var i = 0; i !== recipe.rating; i++)
        rating.push("star");

    const [show, setShow] = useState(false);

    const handleClose = () => setShow(false);
    const handleShow = () => setShow(true);

    return (
        <>
            <RecipeDiv style={{backgroundImage: ("url(/images/" + recipe.image + ")")}}>
                <RecipeOverlay>
                    <SeeMoreBtn onClick={handleShow}><FaPlus style={{cursor: "pointer"}} /></SeeMoreBtn>
                </RecipeOverlay>
                <RecipeDesc>
                    <RecipeName>{recipe.name}</RecipeName>
                    <RatingDiv>
                        {rating.map((value, index) => {
                            return <FaStar key={index} />
                        })}
                    </RatingDiv>
                </ RecipeDesc>
            </RecipeDiv>
            <RecipeModal shown={show} closeFunc={handleClose} recipe={recipe} />
        </>
    )
}

export default RecipeCard
