import {React, useState} from 'react'
import RecipeCard from './RecipeCard'
import styled from 'styled-components';

const ContainerDiv = styled.div`
    background-color: ${props => props.theme.white};
    padding: 1vh;
    display: flex;
    flex-wrap: wrap;
`
const RootContainer = styled.div`
    background-color: ${props => props.theme.white};
`

const FilterInput = styled.input`
    border-radius: 8px;
    border: 1px solid #8888;
    outline: none;
    padding: 0.2rem;
`

const FilterInputDiv = styled.div`
    padding-left: 1vh;
    margin-left: 1rem;
    padding-top: 1vh;
`

const Container = ({recipes}) => {

    const [recipeList, setRecipeList] = useState(recipes);

    const filterRecipes = (e) => {
        let value = e.target.value;
        if(value === '')
            setRecipeList(recipes);
        else
            setRecipeList(recipes.filter(recipe => ((recipe.name).toLowerCase()).includes((value).toLowerCase()) || ((recipe.tags).includes(value.toLowerCase()))));
    };

    return (
        <RootContainer>
            <FilterInputDiv><FilterInput onChange={filterRecipes}></FilterInput></FilterInputDiv>
            <ContainerDiv>
                {recipeList.map ((recipe) => (<RecipeCard key={recipe.id} recipe={recipe} />))}
            </ContainerDiv>
        </RootContainer>
    )
}

export default Container
