import Modal from 'react-bootstrap/Modal';
import Button from 'react-bootstrap/Button';
import styled from 'styled-components';

const Ingredient = styled.li`
    text-transform: capitalize;
`

const RecipeModal = ({ shown, closeFunc, recipe }) => {
    return (
        <Modal size="lg" centered show={shown}>
            <Modal.Header>
                <Modal.Title>{recipe.name}</Modal.Title>
            </Modal.Header>
            <Modal.Body>
                <h4>Ingredients: </h4>
                <ul>{recipe.ingredients.map ((ing, index) => (<Ingredient key={index}>{ing.quantity} {ing.unit} {ing.name}</Ingredient>))}</ul>
                <hr></hr>
                <h4>Instructions: </h4>
                <ul>{recipe.instructions.map ((ins, index) => (<li key={index}>{ins}</li>))}</ul>
            </Modal.Body>
            <Modal.Footer>
                <Button variant="danger" onClick={closeFunc}>Close</Button>
            </Modal.Footer>
        </Modal>
    )
}

export default RecipeModal
